INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 53, 2, 0.0, 10113002, "ミッションをクリアして、\n報酬をゲットしましょう！", 190801, 3.099, "2023/02/14 12:00:00", 2, 10113, -416.5, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 54, 2, 0.0, 10113003, "受け取ることができる\n報酬があるようです\n確認してみてください", 190801, 2.801, "2023/02/14 12:00:00", 3, 10113, -416.5, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 54, 2, 0.0, 10113004, "報酬がもらえますよ！\nチェックしてみてください", 190801, 0.0, "2023/02/14 12:00:00", 4, 10113, -416.5, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 57, 1, 0.0, 10113005, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 190801, 0.0, "2023/02/14 12:00:00", 5, 10113, -416.5, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 55, 2, 0.0, 10113006, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 190801, 5.506, "2023/02/14 12:00:00", 1, 10113, -363.0, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 55, 1, 0.0, 10113007, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 190801, 1.216, "2023/02/14 12:00:00", 2, 10113, -363.0, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 56, 1, 0.0, 10113008, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 190801, 1.539, "2023/02/14 12:00:00", 3, 10113, -363.0, "カリン", "2023/02/26 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 56, 1, 0.0, 10113009, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 190801, 1.875, "2023/02/14 12:00:00", 4, 10113, -363.0, "カリン", "2023/02/26 14:59:59");
