INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 57, 1, 0.0, 20033005, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 190801, 0.0, "2022/11/17 15:00:00", 5, 20033, -416.5, "カリン", "2030/01/01 14:59:59");
