INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 54, 2, 0.0, 20043003, "受け取ることができる\n報酬があるようです\n確認してみてください", 190801, 2.801, "2023/08/18 15:00:00", 3, 20043, -416.5, "カリン", "2030/01/01 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 54, 2, 0.0, 20043004, "報酬がもらえますよ！\nチェックしてみてください", 190801, 0.0, "2023/08/18 15:00:00", 4, 20043, -416.5, "カリン", "2030/01/01 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 57, 1, 0.0, 20043005, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 190801, 0.0, "2023/08/18 15:00:00", 5, 20043, -416.5, "カリン", "2030/01/01 14:59:59");
INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (1, 55, 2, 0.0, 20043006, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 190801, 5.506, "2023/08/18 15:00:00", 1, 20043, -363.0, "カリン", "2030/01/01 14:59:59");
