INSERT INTO `v1_99293b0ee01accdd3f7f7eba6e7faa0590ae07917f0a7a6740e57113a45e13f8` VALUES (2, 56, 1, 0.0, 20043008, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 190801, 1.539, "2023/08/18 15:00:00", 3, 20043, -363.0, "カリン", "2030/01/01 14:59:59");
